{
  "executive_summary": "Design a unified API Gateway architecture for a logistics platform serving three distinct consumer types (mobile, B2B partners, internal services). The gateway centralizes authentication, rate limiting, and traffic isolation — replacing the current inconsistent per-service implementations. The architecture uses a single gateway deployment with three logical ingress paths, each enforcing consumer-specific policies, fronting a shared set of backend services via an internal mesh.",

  "architecture": {
    "components": [
      {
        "name": "API Gateway (Edge)",
        "responsibility": "Single entry point for all external traffic. Terminates TLS, routes requests, enforces authentication, applies rate limiting, and performs request/response transformation. Runs as a cluster behind a load balancer.",
        "boundaries": "Handles ONLY cross-cutting concerns (auth, rate limiting, routing, logging, CORS). Contains ZERO business logic. Never accessed by internal services."
      },
      {
        "name": "Mobile Ingress Pipeline",
        "responsibility": "Gateway route group for mobile consumers. Enforces JWT/OAuth2 bearer token authentication, 100 req/min per-user rate limiting, and mobile-specific response shaping (e.g., pagination defaults, field filtering).",
        "boundaries": "Routes prefixed /api/v{n}/mobile/*. Only accepts tokens issued by the Auth Service. Rate limit keyed on authenticated user ID."
      },
      {
        "name": "Partner Ingress Pipeline",
        "responsibility": "Gateway route group for B2B partners. Enforces API key authentication (via X-API-Key header), 1,000 req/min per-partner rate limiting, request logging for billing/audit, and webhook registration management.",
        "boundaries": "Routes prefixed /api/v{n}/partner/*. API keys validated against Partner Registry. Rate limit keyed on partner ID derived from API key."
      },
      {
        "name": "Internal Service Mesh",
        "responsibility": "Separate network plane for service-to-service communication. No authentication overhead, but enforces mTLS for transport security and network-level isolation from external traffic.",
        "boundaries": "Accessible ONLY from the private VPC/cluster network. Not routable from the internet. Services communicate directly or via internal load balancer — never through the edge gateway."
      },
      {
        "name": "Auth Service",
        "responsibility": "Issues and validates JWT tokens for mobile users. Manages OAuth2 flows (login, refresh, revocation). Single source of truth for user identity.",
        "boundaries": "Stateless token validation (public key verification). Token issuance is stateful (backed by user store). Gateway calls this only for token introspection when needed; prefers local JWT validation."
      },
      {
        "name": "Partner Registry",
        "responsibility": "Manages partner API keys, webhook subscriptions, and partner metadata. Provides key-to-partner resolution for the gateway.",
        "boundaries": "Owns partner identity and configuration. Does NOT own partner business data (shipments, orders, etc.)."
      },
      {
        "name": "Rate Limiter (Distributed)",
        "responsibility": "Centralized rate limiting backed by a shared Redis cluster using sliding window counters. Gateway instances call this as a plugin/sidecar to enforce per-consumer limits.",
        "boundaries": "Stateless logic, stateful store (Redis). Keyed by consumer type + consumer ID. Separate limit tiers configurable per route group."
      },
      {
        "name": "Webhook Dispatcher",
        "responsibility": "Reliably delivers event notifications to partner-registered webhook endpoints. Handles retries with exponential backoff, dead-letter queue, and delivery status tracking.",
        "boundaries": "Consumes domain events from internal services. Owns delivery guarantees — NOT event semantics. Partners manage subscriptions via the Partner Ingress Pipeline."
      },
      {
        "name": "Backend Services (Shipments, Orders, Tracking, etc.)",
        "responsibility": "Core business logic services. Operate behind the gateway, unaware of consumer type. Receive pre-authenticated requests with consumer context in headers.",
        "boundaries": "Never handle auth or rate limiting. Receive X-Consumer-Type, X-Consumer-ID, X-Partner-ID headers injected by the gateway. Trust these headers because traffic originates only from gateway or internal mesh."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "API Gateway (Mobile Ingress)",
        "contract": "HTTPS with Bearer JWT in Authorization header. Standard REST. Gateway validates JWT signature locally using Auth Service public keys (JWKS endpoint, cached).",
        "coupling_type": "loose — standard OAuth2/JWT, no proprietary auth"
      },
      {
        "from": "Partner Systems",
        "to": "API Gateway (Partner Ingress)",
        "contract": "HTTPS with X-API-Key header. REST + webhook callbacks. Gateway resolves API key to partner ID via Partner Registry (cached with TTL).",
        "coupling_type": "loose — API key is opaque identifier, partner decoupled from internals"
      },
      {
        "from": "API Gateway",
        "to": "Rate Limiter (Redis)",
        "contract": "Gateway plugin issues CHECK(key, limit, window) before routing. Returns allow/deny + remaining quota. Quota info returned to caller in X-RateLimit-* response headers.",
        "coupling_type": "tight runtime dependency — gateway cannot route without rate limiter. Mitigated by fail-open policy with alerting."
      },
      {
        "from": "API Gateway",
        "to": "Backend Services",
        "contract": "Internal HTTP/gRPC. Gateway strips external auth headers, injects trusted X-Consumer-Type (mobile|partner|internal), X-Consumer-ID, X-Request-ID. Backend services treat these as authoritative.",
        "coupling_type": "loose — backend services are consumer-agnostic, gateway owns the mapping"
      },
      {
        "from": "Internal Services",
        "to": "Internal Service Mesh",
        "contract": "Direct service-to-service calls over mTLS within private network. Service discovery via DNS or service registry. No gateway involvement.",
        "coupling_type": "medium — mTLS coupling for transport, but service interfaces are independent"
      },
      {
        "from": "Backend Services",
        "to": "Webhook Dispatcher",
        "contract": "Domain events published to message broker (e.g., shipment.delivered, order.created). Webhook Dispatcher subscribes and maps events to partner webhook subscriptions.",
        "coupling_type": "loose — async event-driven, publishers don't know about webhooks"
      },
      {
        "from": "Webhook Dispatcher",
        "to": "Partner Systems",
        "contract": "HTTPS POST to partner-registered URLs with HMAC-SHA256 signature in X-Webhook-Signature header. Retry with exponential backoff (1s, 5s, 30s, 5m, 30m). Dead-letter after 5 failures.",
        "coupling_type": "loose — fire and forget with retries, partner endpoint is opaque"
      }
    ],
    "data_flow": "External request → Load Balancer → API Gateway → [1. TLS termination] → [2. Route classification: mobile/partner based on path prefix] → [3. Authentication: JWT validation for mobile, API key lookup for partner] → [4. Rate limit check against Redis sliding window] → [5. Header injection: X-Consumer-Type, X-Consumer-ID] → [6. Route to backend service] → Backend processes request → Response flows back through gateway (response transformation, CORS headers, rate limit headers). Internal services bypass the gateway entirely, communicating over the private mesh with mTLS. Webhook flow: backend emits domain event → message broker → Webhook Dispatcher → partner endpoint.",
    "patterns_used": [
      {
        "pattern": "API Gateway (Edge Gateway)",
        "rationale": "Centralizes cross-cutting concerns that are currently scattered inconsistently across services. Single enforcement point eliminates auth and rate limiting drift."
      },
      {
        "pattern": "Route-based Consumer Segregation",
        "rationale": "Separate path prefixes (/mobile/*, /partner/*) allow distinct policy pipelines without deploying separate gateway instances. Simpler to operate than multiple gateways while maintaining clear separation."
      },
      {
        "pattern": "Sliding Window Rate Limiting (Redis-backed)",
        "rationale": "Sliding window provides smoother rate enforcement than fixed windows (no burst-at-boundary problem). Redis provides distributed state across gateway instances. Well-understood, battle-tested."
      },
      {
        "pattern": "Strangler Fig Migration",
        "rationale": "Services currently handle their own auth. Migrate one service at a time behind the gateway, removing per-service auth as each is onboarded. Avoids big-bang cutover risk."
      },
      {
        "pattern": "Async Event-Driven Webhooks",
        "rationale": "Decouples webhook delivery from request processing. Backend services publish domain events; a dedicated dispatcher handles delivery reliability. Services don't need to know about partners."
      },
      {
        "pattern": "Network-Level Isolation (Internal Mesh)",
        "rationale": "Internal services are isolated by network topology, not application-level auth. Simpler, faster, and eliminates the overhead of unnecessary auth for trusted traffic."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Consumer Identity & Access",
        "classification": "supporting",
        "aggregates": ["UserAccount", "PartnerCredential", "APIKey", "Session"]
      },
      {
        "name": "Traffic Management",
        "classification": "generic",
        "aggregates": ["RateLimitPolicy", "RouteConfiguration", "ConsumerQuota"]
      },
      {
        "name": "Partner Integration",
        "classification": "supporting",
        "aggregates": ["Partner", "WebhookSubscription", "WebhookDelivery"]
      },
      {
        "name": "Logistics Core (Shipments, Orders, Tracking)",
        "classification": "core",
        "aggregates": ["Shipment", "Order", "TrackingEvent"]
      }
    ],
    "context_map": [
      {
        "upstream": "Consumer Identity & Access",
        "downstream": "Traffic Management",
        "relationship": "Conformist — Traffic Management consumes identity tokens/keys as-is from the identity context without translation"
      },
      {
        "upstream": "Logistics Core",
        "downstream": "Partner Integration",
        "relationship": "Customer-Supplier — Logistics Core publishes domain events that Partner Integration consumes for webhook delivery. Core does not depend on or know about Partner Integration."
      },
      {
        "upstream": "Traffic Management",
        "downstream": "Logistics Core",
        "relationship": "Open Host Service — Gateway exposes a standardized interface; backend services conform to the header contract (X-Consumer-*) injected by the gateway."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single gateway deployment with route-based segregation rather than separate gateway instances per consumer type",
      "gains": "Lower operational complexity, single deployment pipeline, shared observability, easier to maintain consistent behavior",
      "sacrifices": "A gateway failure affects all consumer types simultaneously. Configuration complexity grows as consumer-specific policies accumulate in one place.",
      "alternatives_considered": [
        "Separate gateway per consumer type — better blast radius isolation but 3x operational burden and harder to keep consistent",
        "BFF (Backend for Frontend) pattern — mobile BFF + partner BFF, each with own gateway logic. Better separation but duplicates cross-cutting concerns."
      ]
    },
    {
      "decision": "Redis-backed distributed rate limiting with fail-open policy",
      "gains": "Accurate distributed counting across gateway instances. Fail-open prevents Redis outage from causing total traffic block.",
      "sacrifices": "Fail-open means a Redis outage temporarily disables rate limiting — a brief window of unprotected access. Redis adds an infrastructure dependency.",
      "alternatives_considered": [
        "Local in-memory rate limiting — simpler but inaccurate with multiple gateway instances (each instance counts independently)",
        "Fail-closed policy — safer but a Redis outage would reject all traffic, worse than brief over-admission"
      ]
    },
    {
      "decision": "Network-level isolation for internal services (no gateway, no app-level auth) instead of zero-trust internal auth",
      "gains": "Significantly simpler internal communication. No auth overhead on hot internal paths. Faster service-to-service calls.",
      "sacrifices": "If the network perimeter is breached, internal services are unprotected at the application layer. Requires strict network policy enforcement.",
      "alternatives_considered": [
        "Zero-trust with mTLS + JWT for all internal calls — more secure but adds latency, complexity, and certificate management burden for traffic that's already on a private network",
        "Service mesh with sidecar proxies (e.g., Istio/Linkerd) — provides mTLS transparently but adds significant operational complexity"
      ]
    },
    {
      "decision": "Strangler fig migration from per-service auth to centralized gateway auth",
      "gains": "Zero-downtime migration. Each service can be moved independently. Easy rollback per service.",
      "sacrifices": "During migration, the system runs a hybrid model where some services use gateway auth and others still do their own. Requires careful tracking of migration state.",
      "alternatives_considered": [
        "Big-bang cutover — move all services behind gateway at once. Simpler end state but high risk of coordinated failure."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Rate limit tiers",
      "evolution_path": "Rate limits are configured per route group and per consumer. Adding new tiers (e.g., premium partners at 5,000 req/min) requires only configuration changes in the gateway + Redis policy, no code changes."
    },
    {
      "area": "Authentication methods",
      "evolution_path": "Auth is handled as pluggable middleware per ingress pipeline. Adding new auth methods (e.g., OAuth2 for partners, mutual TLS for premium partners) means adding a new auth plugin without changing routing or backend services."
    },
    {
      "area": "New consumer types",
      "evolution_path": "Adding a fourth consumer type (e.g., admin dashboard) means adding a new route prefix and policy pipeline in the gateway. Backend services are consumer-agnostic — they just read X-Consumer-Type headers."
    },
    {
      "area": "Webhook event types",
      "evolution_path": "New domain events from backend services are automatically available for webhook subscription. The Webhook Dispatcher subscribes to all events on the broker; partners choose which to receive."
    }
  ],

  "rigidity_points": [
    {
      "area": "Gateway as single external entry point",
      "reason": "ALL external traffic MUST flow through the gateway. No exceptions. This is a deliberate rigidity — it ensures auth and rate limiting cannot be bypassed. Any 'shortcut' that routes around the gateway is a security violation."
    },
    {
      "area": "X-Consumer-* header contract",
      "reason": "Backend services MUST trust and use these headers for consumer identification. This contract must be stable — changing header names or semantics requires coordinated changes across all backend services."
    },
    {
      "area": "Network isolation boundary",
      "reason": "Internal services MUST NOT be reachable from external networks. This is enforced at the infrastructure level (VPC/network policy) and is non-negotiable for the security model to hold."
    }
  ],

  "risks": [
    {
      "risk": "Gateway becomes a single point of failure — all external traffic depends on it",
      "severity": "critical",
      "mitigation": "Deploy gateway as a horizontally scaled cluster (minimum 3 instances) behind a load balancer with health checks. Use blue-green or canary deployments for gateway updates. Monitor gateway latency p99 aggressively — any degradation affects all consumers."
    },
    {
      "risk": "Redis failure disables rate limiting under fail-open policy, allowing unbounded traffic to hit backend services",
      "severity": "high",
      "mitigation": "Redis deployed as a cluster with replication and automatic failover. Circuit breaker on Redis calls with aggressive alerting on open state. Implement local fallback rate limiting (approximate, per-instance) when Redis is unavailable. Backend services should have their own resource limits (connection pools, thread pools) as defense in depth."
    },
    {
      "risk": "Migration period creates inconsistent auth enforcement — some services behind gateway, others doing their own auth",
      "severity": "high",
      "mitigation": "Maintain a migration tracking dashboard. During migration, gateway-onboarded services MUST reject requests not coming from the gateway (check for presence of X-Consumer-Type header from trusted source IP). Set a hard deadline to complete migration."
    },
    {
      "risk": "Gateway latency overhead on every request",
      "severity": "medium",
      "mitigation": "JWT validation is local (no network call) — just public key verification from cached JWKS. API key validation uses a local cache with short TTL. Rate limit check is a single Redis call (~1ms). Target: <5ms p99 gateway overhead. Monitor continuously."
    },
    {
      "risk": "Partner webhook delivery failures cause data loss or partner SLA breaches",
      "severity": "medium",
      "mitigation": "Webhook Dispatcher persists all events to durable store before attempting delivery. Dead-letter queue with manual replay capability. Partner-facing webhook delivery status API so partners can self-diagnose. Configurable retry policy per partner."
    },
    {
      "risk": "Trusted header injection (X-Consumer-*) could be spoofed if a backend service is accidentally exposed externally",
      "severity": "high",
      "mitigation": "Backend services MUST strip any incoming X-Consumer-* headers and only trust those from known gateway IPs / internal mesh. Network policies enforce that backend services are unreachable from external networks. Regular security audits of network exposure."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-2): Deploy API gateway (Kong, AWS API Gateway, or Envoy-based — choose based on existing infrastructure) with mobile ingress pipeline only. Implement JWT validation and 100 req/min rate limiting. Migrate 1-2 non-critical services behind the gateway using strangler fig. Phase 2 (Weeks 3-4): Add partner ingress pipeline with API key auth and 1,000 req/min rate limiting. Build Partner Registry service. Migrate remaining services behind gateway. Phase 3 (Weeks 5-6): Build Webhook Dispatcher with reliable delivery. Implement partner webhook subscription management via Partner Ingress. Phase 4 (Week 7+): Remove all per-service auth implementations. Harden network isolation. Complete migration tracking. Load test gateway at 2x expected peak traffic.",
    "files_to_create_or_modify": [
      "infrastructure/api-gateway/gateway-config.yaml — Gateway route definitions, plugin configuration, upstream service mapping",
      "infrastructure/api-gateway/rate-limit-policies.yaml — Per-consumer-type rate limit configurations",
      "infrastructure/api-gateway/auth-plugins/ — JWT validation plugin config, API key validation plugin config",
      "services/partner-registry/ — New service: API key management, partner metadata, webhook subscription CRUD",
      "services/webhook-dispatcher/ — New service: event consumer, delivery engine, retry logic, dead-letter management",
      "infrastructure/network-policies/ — VPC/Kubernetes network policies isolating internal services from external traffic",
      "libs/shared/middleware/trusted-headers.ts — Middleware for backend services to validate X-Consumer-* headers come from trusted sources",
      "docs/adr/001-api-gateway-introduction.md — Architecture Decision Record documenting this design",
      "docs/migration-checklist.md — Per-service migration tracking from direct-auth to gateway-auth"
    ],
    "patterns_to_follow": "Use the gateway ONLY for cross-cutting concerns — never put business logic in gateway plugins. Backend services must remain consumer-agnostic; they read X-Consumer-Type but do not branch on it for business logic (use feature flags or separate endpoints if behavior must differ). Rate limiting keys must always include consumer ID to prevent one user from exhausting another's quota. All gateway configuration should be declarative (YAML/config files) and version-controlled, not configured via admin UI.",
    "pitfalls_to_avoid": [
      "Do NOT put business logic in the gateway — it becomes an unmaintainable monolith. The gateway handles routing, auth, rate limiting, and nothing else.",
      "Do NOT use a single rate limit bucket for all mobile users — key on user ID, not client type. Otherwise one heavy user blocks everyone.",
      "Do NOT skip the migration tracking — running hybrid auth (some services gateway-auth, some self-auth) without tracking which is which is a security audit nightmare.",
      "Do NOT hardcode rate limits — make them configurable per consumer and per route. Partner limits will need to vary by partner tier.",
      "Do NOT make internal services call through the gateway — this adds unnecessary latency and creates circular dependencies. Internal mesh is separate.",
      "Do NOT forget to strip/validate X-Consumer-* headers at backend services — if any backend is accidentally exposed, spoofed headers would bypass auth.",
      "Do NOT implement webhook delivery synchronously in the request path — use async event-driven delivery via a message broker."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Gateway pattern selection — this is a textbook use case for an API gateway with well-established solutions",
      "Rate limiting approach — sliding window with Redis is industry standard for distributed rate limiting",
      "Consumer segregation via route groups — cleanly separates policy without infrastructure duplication",
      "Strangler fig migration — safest path from current inconsistent per-service auth to centralized gateway"
    ],
    "low_confidence_areas": [
      "Specific gateway technology choice (Kong vs Envoy vs cloud-native) — depends on existing infrastructure, team expertise, and cloud provider which are unknown",
      "Exact internal service mesh topology — depends on deployment platform (Kubernetes, ECS, VMs) which is unspecified",
      "Webhook delivery SLA requirements — retry policy and dead-letter behavior depend on partner contracts not provided"
    ],
    "assumptions": [
      "The platform runs on a cloud provider or container orchestrator that supports network-level isolation (VPC, Kubernetes NetworkPolicy, etc.)",
      "Backend services are already deployed as independent services (not a monolith) — the architecture diagram shows them as separate services",
      "The team has operational capacity to manage a Redis cluster for rate limiting state",
      "JWT is acceptable for mobile auth — no requirement for opaque tokens or session-based auth was mentioned",
      "Partner count is in the tens-to-hundreds range, not millions — API key lookup caching strategy depends on this"
    ]
  }
}

